import React, { useState, useEffect } from 'react';
import api from '../services/api';
import './Dashboard.css';

const Dashboard = () => {
  const [stats, setStats] = useState({
    ordersToday: 0,
    revenueToday: 0,
    activeTables: 0,
    pendingOrders: 0,
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const [ordersRes, tablesRes] = await Promise.all([
        api.get('/orders'),
        api.get('/tables'),
      ]);

      const orders = ordersRes.data;
      const today = new Date().toISOString().split('T')[0];
      const ordersToday = orders.filter(
        (order) => order.createdAt?.split('T')[0] === today
      );
      const revenueToday = ordersToday
        .filter((o) => o.paymentStatus === 'paid')
        .reduce((sum, o) => sum + (o.totalAmount || 0), 0);
      const pendingOrders = orders.filter((o) => 
        ['pending', 'preparing'].includes(o.status)
      ).length;
      const activeTables = tablesRes.data.filter(
        (t) => t.status === 'occupied'
      ).length;

      setStats({
        ordersToday: ordersToday.length,
        revenueToday,
        activeTables,
        pendingOrders,
      });
    } catch (error) {
      console.error('Error fetching stats:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="loading">Loading dashboard...</div>;
  }

  return (
    <div className="dashboard">
      <div className="page-header">
        <h1>Dashboard</h1>
      </div>
      <div className="stats-grid">
        <div className="stat-card">
          <h3>Orders Today</h3>
          <p className="stat-value">{stats.ordersToday}</p>
        </div>
        <div className="stat-card">
          <h3>Revenue Today</h3>
          <p className="stat-value">₹{stats.revenueToday.toFixe}</p>
        </div>
        <div className="stat-card">
          <h3>Active Tables</h3>
          <p className="stat-value">{stats.activeTables}</p>
        </div>
        <div className="stat-card">
          <h3>Pending Orders</h3>
          <p className="stat-value">{stats.pendingOrders}</p>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
